var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"안녕! 사장님! 안녕!","JPN":"やほやほー！　社長！　やほー！","ENG":"Hi, Boss! Hi!","TWN":"你好！老闆！你好！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"응? 아까도 인사했으니 괜찮다니?","JPN":"え？　さっきも挨拶したからもう大丈夫って？","ENG":"Mm? I don't have to say hello multiple times?","TWN":"嗯？你好說一次就好，不需要說那麼多次嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그치만 인사는 여러 번 해도 기분이 좋잖아?","JPN":"でも、挨拶って何回しても気持ちいいじゃない？","ENG":"But I like saying hello multiple times.","TWN":"可是…你不覺得就算說很多次，還是很開心嗎！？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"난 사장님을 볼 때마다 반가운 걸!","JPN":"私は社長に会うたびに嬉しくなるんだ！","ENG":"I'm always so happy to see you!","TWN":"因為我每次見到老闆都超～～開心！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그리구 사장님은 매일 인사를 잘 해주니까! 그래서 좋아!","JPN":"あとね、社長は毎日私にも挨拶してくれるから！　だから好き！","ENG":"Also, you say hello to me all the time, which is all the more reason to say hello to you!","TWN":"而且老闆每天都會跟我打招呼！ 所以我也喜歡跟老闆打招呼！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"히히- 있지, 있지!","JPN":"ヘヘッ！　あのね、あのね！","ENG":"Teehee! You know what?","TWN":"嘻嘻～你知道嗎！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"나한테는 손을 같이 흔들어주는 사람이 있다는 게 정말로 기뻐!","JPN":"私はね、一緒に手を振ってくれる人がいて本当に嬉しいの！","ENG":"I'm happy when you wave back at me.","TWN":"我真的很開心有人和我一起揮手打招呼！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"예전엔 만나는 사람들이 모두 나한테 인사해주는 게 소원이었거든.","JPN":"昔はね、出会った人たちが私に挨拶をしてくれるのが願いだったの。","ENG":"Before, it was my wish that everyone would say hello to me.","TWN":"以前我的願望，就是希望見到我的人每個人都跟我打招呼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그래서 그렇게 해달라고 밤마다 별님한테 기도도 해봤어!","JPN":"だから、毎日夜空のお星様に願いを込めてお祈りしていたんだ！","ENG":"I even prayed to the stars every night.","TWN":"所以我每天晚上都會向天上的星星祈禱，希望可以實現願望！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"하지만 이젠 괜찮아! 소원을 비는 것보다 더 좋은 방법을 알고 있으니까!","JPN":"でももう大丈夫！　願い事をするより、もっといい方法を知ってるからね！","ENG":"But now, I don't. I've found a better solution than prayers.","TWN":"但是現在我不用再祈禱了！ 因爲我已經知道比許願更好的方法！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"이젠 알아! 날 기억해주는 친구 한 명이 그런 소원보다 백 배 천 배 소중하다는 걸 말야!","JPN":"もうわかってるの！　私を憶えていてくれる友達一人のほうが、願い事より100倍も、200倍も大切ってことをね！","ENG":"Now, I know having one friend who remembers me is much, much better than making a wish upon a star.","TWN":"因為我終於知道！有一個會把我記在心上的人，比那個願望更珍貴千百倍！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그러니까! 사장님은 앞으로도 쭉 친구로 남아줘! 약속!","JPN":"だから、社長はこれからもずっと友達でいてね！　約束だよー！","ENG":"So... Boss, let's be best friends forever. Promise?","TWN":"所以老闆！以後也要繼續跟我做朋友喔！打勾勾！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};